def sum_amicable_numbers(N):
    def sum_proper_divisors(n):
        if n <= 1:
            return 0
        sum = 1  # 1 is a proper divisor of all numbers greater than 1
        for i in range(2, n):
            if n % i == 0:
                sum += i
        return sum
    amicable = set()
    for i in range(1, N+1):
        j = sum_proper_divisors(i)
        if 1 <= j <= N and j not in amicable:
            amicable.add(i)
            amicable.add(j)
    return sum(amicable)

# Test cases
assert sum_amicable_numbers(999) == 504
assert sum_amicable_numbers(9999) == 31626
assert sum_amicable_numbers(99) == 0
